export class Font {
  readonly cssFontString: string;
  readonly baselineAdjustment: number;

  private constructor(readonly sizeInPixels: number, toCssFontString: (sizeInPixels: number) => string) {
    this.cssFontString = toCssFontString(sizeInPixels);
    this.baselineAdjustment = Math.round(sizeInPixels / 3);
  }

  static readonly button = new Font(18, (sizeInPixels) => `400 ${sizeInPixels}px Inter`);
  static readonly buttonBig = new Font(36, (sizeInPixels) => `400 ${sizeInPixels}px Inter`);
  static readonly buttonHuge = new Font(54, (sizeInPixels) => `400 ${sizeInPixels}px Inter`);
  static readonly buttonSmall = new Font(12, (sizeInPixels) => `400 ${sizeInPixels}px Inter`);
  static readonly selector = new Font(16, (sizeInPixels) => `400 ${sizeInPixels}px Inter`);
  static readonly joystick = new Font(12, (sizeInPixels) => `500 ${sizeInPixels}px Inter`);
  static readonly pad = new Font(14, (sizeInPixels) => `${sizeInPixels}px Inter`);
}
