const NUM_VOICES = 8;

// ----- interface w/ worklet -----

class Voice {
  readonly params = new Float32Array<any>(new SharedArrayBuffer(128 * 4));

  constructor(
    readonly synth: Synth,
    readonly channel: number,
  ) { }

  note = -1;

  noteOn(note: number, velocity: number) {
    if (this.isOn) {
      this.noteOff(this.note, 127);
    }
    this.note = note;
    this.synth.sendToWorklet({
      command: 'process midi message',
      data: midi.noteOn(this.channel, note, velocity),
    });
  }

  noteOff(note: number, velocity: number) {
    this.note = -1;
    this.synth.sendToWorklet({
      command: 'process midi message',
      data: midi.noteOff(this.channel, note, velocity),
    });
  }

  get isOn() {
    return this.note !== -1;
  }

  get freq() {
    return toFrequency(this.note) * Math.pow(2, this.params[P_GLIDE] / 12);
  }
}

class Synth {
  patch: Patch;
  mode: Mode = 'mpe';
  worklet: AudioWorkletNode | null = null;
  voices: Voice[] = [];
  octave = 0;
  analyzer: AnalyserNode | null = null;
  timeDomainData: Uint8Array<any> | null = null;

  constructor(patchName: string = 'pwm') {
    const patch = patchLibrary.find((p) => p.settings.name === patchName);
    if (!patch) {
      throw new Error('unknown patch name! ' + patchName);
    }

    this.patch = patch;
    for (let ch = 0; ch < NUM_VOICES; ch++) {
      this.voices.push(new Voice(this, ch));
    }
  }

  private _seq: Sequencer | null = null;
  get seq() {
    return this._seq ?? (this._seq = new Sequencer(this));
  }

  private _arp: Arpeggiator | null = null;
  get arp() {
    return this._arp ?? (this._arp = new Arpeggiator(this));
  }

  init() {
    this.worklet = new AudioWorkletNode(context, 'msynth');
    this.sendToWorklet({
      command: 'init',
      voiceParams: this.voices.map((voice) => voice.params.buffer),
    });
    this.loadAiModules(localStorage.getItem(AI_MODULES_KEY) ?? '');

    this.analyzer = context.createAnalyser();
    // Keep buffer short so the scope shows recent audio (~43 ms at 48 kHz), not ~0.7 s ago
    this.analyzer.fftSize = 2048;
    const bufferLength = this.analyzer.fftSize;
    this.timeDomainData = new Uint8Array(bufferLength);

    // Important!
    this.worklet.channelInterpretation = 'discrete';
    this.worklet.channelCount = 2;
    this.worklet.channelCountMode = 'explicit';
    this.worklet.connect(this.analyzer).connect(context.destination);
    registerMicConsumer(this.worklet);
    this.worklet.port.onmessage = (msg) => this.seq.onMessageFromWorklet(msg.data as MessageFromWorklet);

    this.loadPatch(this.patch);
  }

  getTimeDomainData(): Uint8Array | null {
    if (!this.analyzer || !this.timeDomainData) {
      return null;
    }

    this.analyzer.getByteTimeDomainData(this.timeDomainData!);
    return this.timeDomainData;
  }

  sendToWorklet(message: MessageToWorklet) {
    this.worklet?.port.postMessage(message);
  }

  loadAiModules(aiModulesTsCode: string) {
    console.log('loading ai modules', aiModulesTsCode);
    this.sendToWorklet({
      command: 'load ai modules',
      code: aiModulesTsCode,
    });
  }

  loadPatch(patch: Patch, loadInEditor = true) {
    this.patch = patch;
    console.log('loading patch', patch.code);
    this.sendToWorklet({
      command: 'load patch',
      code: patch.code,
      mono: patch.settings.mono,
    });
    const tempo = patch.settings.tempo;
    this.setParam(P_GAIN, 0.2);
    this.setParam(P_TEMPO, tempo);
    this.setParam(P_PARAM_A, patch.settings.A);
    this.setParam(P_PARAM_B, patch.settings.B);
    this.setParam(P_PARAM_C, patch.settings.C);
    this.setParam(P_PARAM_D, patch.settings.D);
    this.setParam(P_PARAM_E, patch.settings.E);
    this.setParam(P_PARAM_F, patch.settings.F);
    this.setParam(P_PARAM_G, patch.settings.G);
    this.setParam(P_PARAM_H, patch.settings.H);
    this.setParam(P_PARAM_I, patch.settings.I);
    this.setParam(P_PARAM_J, patch.settings.J);
    this.octave = patch.settings.octave;
    this.mode = patch.settings.mode;

    if (activeSynth === this && loadInEditor) {
      this.loadPatchInEditor();
    }
  }

  loadPatchInEditor() {
    editor.setContents(this.patch.code.trim());
  }

  savePatch() {
    const code = editor.view.state.doc.toString();
    const { settings } = compile(code, loadAiModules()); // will throw if there's an error
    this.patch.code = code;
    this.patch.settings = settings;
    this.loadPatch(this.patch, false);
  }

  grabVoice() {
    if (this.patch.settings.mono) {
      return this.voices.find((v) => v.channel === 0)!;
    }

    const fingers = [...fingersById.values()];
    const midiVoices = new Set(midiNoteVoices.values());
    const freeVoice = this.voices.findLast(
      (v) => !fingers.some((f) => f.voice === v) && !midiVoices.has(v),
    );
    const voice = freeVoice ?? this.voices.at(-1)!; // if there's no free voice, steal the least recently claimed
    this.voices.splice(this.voices.indexOf(voice), 1);
    this.voices.unshift(voice);
    return voice;
  }

  setParam(n: number, value: number) {
    for (const voice of this.voices) {
      voice.params[n] = value;
    }
  }

  lnf = 220;

  getLowestNoteFreq() {
    let lnf = Infinity;
    for (const voice of this.voices) {
      if (voice.isOn && voice.freq < lnf) {
        lnf = voice.freq;
      }
    }
    if (Number.isFinite(lnf)) {
      this.lnf = lnf;
    }
    return this.lnf;
  }

  panic() {
    for (const voice of this.voices) {
      voice.noteOff(voice.note, 127);
    }
  }
}

