const midiNoteVoices = new Map<number, Voice>();

async function setupMidi() {
  if (!navigator.requestMIDIAccess) {
    return;
  }
  const midiAccess = await navigator.requestMIDIAccess();
  const [midiInput] = [...(midiAccess.inputs as any).values()];
  if (midiInput) {
    console.log('midi input', midiInput);
    midiInput.onmidimessage = (e: MIDIMessageEvent) => {
      const [d1, d2, d3] = e.data;
      switch (d1 >> 4) {
        case 0x9: {
          const note = d2;
          const velocity = d3;
          if (velocity === 0) {
            // some devices send noteOn with vel 0 for noteOff!
            midiNoteVoices.get(note)?.noteOff(note, velocity);
            midiNoteVoices.delete(note);
          } else {
            const voice = activeSynth.grabVoice()!;
            midiNoteVoices.set(note, voice);
            voice.params[P_GLIDE] = 0;
            voice.params[P_SLIDE] = 0;
            voice.params[P_PRESSURE] = velocity / 127;
            voice.noteOn(note, velocity);
            activeSynth.seq.onNotePressed(note, midiNoteVoices.size === 1);
          }
          break;
        }
        case 0x8: {
          const note = d2;
          const velocity = d3;
          midiNoteVoices.get(note)?.noteOff(note, velocity);
          midiNoteVoices.delete(note);
          break;
        }
        case 0xE: {
          const value = (((d3 << 7) | d2) - 8192) / 8192;
          const numSemitones = value * (value > 0 ? 3 : 12);
          activeSynth.setParam(P_GLIDE, numSemitones);
          break;
        }
      }
    };
  }
}

try {
  await setupMidi();
} catch (e) {
  console.log('unable to set up midi', e);
}

