const LOW_B = 47;
const PERFECT_4TH = 5;

class Pad extends Thing {
  constructor(
    public col: number,
    public row: number,
    public noteName: string,
  ) {
    super({
      // Width is fixed per pad; height comes from the Row parent.
      w: () => padWidth,
    });
  }

  shift?: {
    render(thisPad: Pad, enabled: boolean): void;
    enabled?(): boolean;
    selected?(): boolean;
    selectedColor?(): string;
    onPointerDown?(): void;
    onPointerUp?(): void;
    onEnter?(): void;
  };

  get note() {
    return LOW_B + 12 * activeSynth.octave + PERFECT_4TH * (7 - this.row) + this.col;
  }

  isBeingPlayedBySequencer = false;

  consumedPointerDown = false;

  onPointerDown(x: number, y: number, e: PointerEvent) {
    if (shift()) {
      this.consumedPointerDown = false;
      if ((this.shift?.enabled?.() ?? true) && this.shift?.onPointerDown) {
        this.shift.onPointerDown();
        this.consumedPointerDown = true;
      }
      return this;
    }

    const somePadsAreTouched = [...fingersById.values()].some((f) => !!f.pad);
    activeSynth.seq.onNotePressed(this.note, !somePadsAreTouched);
    Finger.add(e.pointerId, x, y, getPressure(e));
    return this;
  }

  onPointerUp(x: number, y: number, e: PointerEvent): void {
    if (shift()) {
      if (this.shift?.enabled?.() ?? true) {
        this.shift?.onPointerUp?.();
      }
    }
  }

  onPointerMove(x: number, y: number, e: PointerEvent) {
    if (shift() && !this.consumedPointerDown) {
      const pad = pads.find((pad) => pad.contains(x, y));
      pad?.shift?.onEnter?.();
    }
  }

  render() {
    const x = this.x + 1;
    const y = this.y + 1;
    const w = this.w - 2;
    const h = this.h - 2;

    ctx.save();
    ctx.beginPath();
    ctx.lineWidth = 3;
    ctx.strokeStyle = '#ddd';
    ctx.roundRect(x, y, w, h, ui.RECTANGLE_RADIUS);
    ctx.stroke();

    const isPickColumn = activeSynth.mode === 'strum' && this.col >= ui.LEFTMOST_STRUM_COL;
    if (isPickColumn) {
      ctx.beginPath();
      ctx.save();
      ctx.globalAlpha = 0.2;
      ctx.fillStyle = activeSynthColor();
      ctx.roundRect(x, y, w, h, ui.RECTANGLE_RADIUS);
      ctx.fill();
      ctx.restore();
      drawMaterialOverlay(x, y, w, h);
      ctx.restore();
    } else {
      ctx.beginPath();
      ctx.fillStyle =
        this.noteName === '' ? ui.DARK_BACKGROUND_COLOR : ui.LIGHT_BACKGROUND_COLOR;
      ctx.roundRect(x, y, w, h, ui.RECTANGLE_RADIUS);
      ctx.fill();
      drawMaterialOverlay(x, y, w, h);
    }

    if (this.isBeingPlayedBySequencer) {
      ctx.beginPath();
      ctx.fillStyle =
        this.noteName === ''
          ? ui.PAD_BLACK_KEY_PLAYED_BY_SEQ_COLOR
          : ui.PAD_WHITE_KEY_PLAYED_BY_SEQ_COLOR;
      ctx.roundRect(x + 20, y + 20, w - 40, h - 40, ui.RECTANGLE_RADIUS);
      ctx.fill();
    }

    if (!shift() && !isPickColumn && this.noteName !== '') {
      ctx.globalAlpha = 0.25;
      ctx.beginPath();
      ctx.font = Font.pad.cssFontString;
      ctx.fillStyle = ui.TEXT_COLOR;
      ctx.fillText(this.noteName, x + 4, y + 16);
      ctx.fill();
      ctx.globalAlpha = 1;
    }
    ctx.restore();

    if (shift() && this.shift?.render) {
      const enabled = this.shift.enabled?.() ?? true;
      const selected = this.shift.selected?.() ?? false;
      const selectedColor = this.shift.selectedColor?.() ?? 'rgba(255, 230, 0, 0.95)';

      if (selected) {
        ctx.save();
        ctx.lineWidth = 4;
        ctx.strokeStyle = selectedColor;
        ctx.beginPath();
        ctx.roundRect(x + 4, y + 4, w - 8, h - 8, ui.RECTANGLE_RADIUS);
        ctx.stroke();
        ctx.restore();
      }

      this.shift.render(this, enabled);
    }
  }

  renderShiftLabel(enabled: boolean, ...lines: string[]) {
    if (!enabled) {
      ctx.globalAlpha = 0.25;
    }
    const lineSpacing = 1.25;
    const font = lines.length > 3 ? Font.buttonSmall : lines.some(line => [...line].some(char => char.match(/[a-zA-Z0-9]/))) ? Font.button : Font.buttonBig;
    ctx.font = font.cssFontString;
    ctx.fillStyle = this.noteName !== '' ? ui.TEXT_COLOR : ui.LIGHT_BACKGROUND_COLOR;
    let y = this.centerY + font.baselineAdjustment - Math.max(lines.length - 1, 0) / 2 * lineSpacing * font.sizeInPixels;
    for (const line of lines) {
      ctx.fillText(line, this.centerX - ctx.measureText(line).width / 2, y);
      y += lineSpacing * font.sizeInPixels;
    }
  }
}

const NUM_COLS = 13;
const NUM_ROWS = 6;
const FIRST_ROW = 2;

const pads: Pad[] = [];
const padThing = new Column({ h: () => padWidth * NUM_COLS });
const noteNames = ['C', '', 'D', '', 'E', 'F', '', 'G', '', 'A', '', 'B'];
let noteNameIdxOffset = 0;
for (let rowIdx = FIRST_ROW; rowIdx < FIRST_ROW + NUM_ROWS; rowIdx++) {
  const row = new Row({
    h: () => padHeight,
    w: () => padWidth * NUM_COLS,
  });
  for (let colIdx = 0; colIdx < NUM_COLS; colIdx++) {
    const pad = new Pad(colIdx, rowIdx, noteNames[(noteNameIdxOffset + colIdx) % 12]);
    pads.push(pad);
    row.addChild(pad);
  }
  noteNameIdxOffset += 7;
  padThing.addChild(row);
}

