let shiftIsPressed = false;
let spaceIsPressed = false;

function shift() {
  return msynthButton.isPressed || shiftIsPressed;
}

// Canvas isn't focusable, so key events never fire on it. Use window.
window.addEventListener('keydown', (e) => {
  if (e.repeat) {
    // ignore
  } else if (e.key === 'Shift') {
    shiftIsPressed = true;
  } else if (e.key === ' ') {
    spaceIsPressed = true;
    if (activeTool === activeSynth.seq) {
      activeSynth.seq.startRecording();
    }
  }
});

window.addEventListener('keyup', (e) => {
  if (e.repeat) {
    // ignore
  } else if (e.key === 'Shift') {
    shiftIsPressed = false;
  } else if (e.key === ' ') {
    spaceIsPressed = false;
    if (activeTool === activeSynth.seq) {
      activeSynth.seq.stopRecording();
    }
  }
});

window.addEventListener('keydown', (e) => {
  if (e.key === 'Shift') {
    shiftIsPressed = true;
  }
});

window.addEventListener('keyup', (e) => {
  if (e.key === 'Shift') {
    shiftIsPressed = false;
  }
});

const activeSynthColor = () => activeSynth === synth1 ? ui.SYNTH_1_COLOR : ui.SYNTH_2_COLOR;
const otherSynthColor = () => activeSynth === synth1 ? ui.SYNTH_2_COLOR : ui.SYNTH_1_COLOR;

const msynthButton = new (class extends Button {
  constructor() {
    super({
      w: () => padWidth,
      h: () => padHeight * 2,
      label: () => '',
    });
  }

  isPressed = false;

  onPointerDown() {
    this.isPressed = true;
    return this;
  }

  onPointerUp() {
    this.isPressed = false;
    return this;
  }

  render() {
    super.render();

    const x = this.x + this.w / 2;
    const y = this.y + this.h / 2;

    ctx.translate(x, y);
    ctx.rotate(-Math.PI / 2); // rotate -90 degrees for sideways text

    // Choose biggest font size that fits
    let fontSize = Math.floor(this.h * 0.7); // may overshoot due to rotation
    ctx.font = `bold ${fontSize}px Inter`;
    // Shrink font if too wide even after rotation
    const text = 'MSYNTH';
    const maxHeight = this.h * 0.9;
    let textMetrics = ctx.measureText(text);
    if (textMetrics.width > maxHeight) {
      fontSize = Math.floor(maxHeight * fontSize / textMetrics.width);
      ctx.font = `800 ${fontSize}px Inter`;
      textMetrics = ctx.measureText(text);
    }

    ctx.scale(1, this.w * 1 / fontSize);
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillStyle = activeSynthColor();
    ctx.globalAlpha = 0.25;
    ctx.fillText(text, 0, 0);
  }
})();

type TempoSource = 'auto' | 'free' | 'synth 1' | 'synth 2';
const tempoWidget = new (class extends Thing {
  private source: TempoSource = 'auto';
  private _value = 120;

  constructor() {
    super({
      w: () => padWidth,
      h: () => padHeight * 2,
      isActive: () => true,
      hasBackground: true
    });
    this.addChild(new EmbeddedSelector<TempoSource>({
      values: ['auto', 'free', 'synth 1', 'synth 2'],
      getValue: () => this.source,
      setValue: (value) => {
        this.source = value;
      },
      valueToString: (value) => value,
    }), 'bottom center');
  }

  get foregroundColor() {
    return this.source === 'synth 1' ? ui.SYNTH_1_COLOR : this.source === 'synth 2' ? ui.SYNTH_2_COLOR : '#000';
  }

  get value() {
    switch (this.source) {
      case 'auto':
        return synth1.patch.settings.tempo ?? synth2.patch.settings.tempo ?? this._value;
      case 'synth 1':
        return synth1.patch.settings.tempo ?? this._value;
      case 'synth 2':
        return synth2.patch.settings.tempo ?? this._value;
      case 'free':
        return this._value;
    }
  }

  private pointerDownY?: number;
  private pointerDownValue?: number;

  onPointerDown(x: number, y: number, e: PointerEvent) {
    this.pointerDownY = y;
    this.pointerDownValue = this.value;
    return this;
  }

  onPointerMove(x: number, y: number, e: PointerEvent) {
    const dy = this.pointerDownY! - y;
    if (this.source !== 'free' && Math.abs(dy) > 5) {
      this._value = this.pointerDownValue = this.value;
      this.source = 'free';
    }
    if (this.source === 'free') {
      this._value = Math.round(clamp(this.pointerDownValue! + dy / 10, 10, 200));
    }
  }

  onPointerUp(x: number, y: number, e: PointerEvent) {
    this.pointerDownY = undefined;
    this.pointerDownValue = undefined;
  }

  render() {
    super.render();
    const color = this.source === 'synth 1' ? ui.SYNTH_1_COLOR : this.source === 'synth 2' ? ui.SYNTH_2_COLOR : '#000';
    this.renderLabel('tempo', Font.buttonSmall, this.centerX, this.centerY - Font.buttonBig.sizeInPixels, color, 0.5);
    this.renderLabel('' + this.value, Font.buttonBig, this.centerX, this.centerY, color, 1);

    synth1.setParam(P_TEMPO, this.value);
    synth2.setParam(P_TEMPO, this.value);
  }
})();

