// Finger creation is handled by the pads themselves, but the handlers below
// are needed for move/lift.

canvas.addEventListener('pointermove', (e) => {
  const finger = fingersById.get(e.pointerId);
  if (finger) {
    finger.move(e.offsetX, e.offsetY, getPressure(e));
    e.preventDefault();
  }
});

canvas.addEventListener('pointerup', onPointerUp);
canvas.addEventListener('pointercancel', onPointerUp);

function onPointerUp(e: PointerEvent) {
  const finger = fingersById.get(e.pointerId);
  if (finger) {
    fingersById.delete(e.pointerId);
    finger.lift();
  }
  canvas.releasePointerCapture(e.pointerId);
}

function render() {
  ctx.clearRect(0, 0, innerWidth, innerHeight);

  const padsBottomY = (FIRST_ROW + NUM_ROWS) * padHeight;
  const editorClosedTop = padsBottomY - ui.EDITOR_BUTTON_BAR_HEIGHT;
  const editorOpenTop = padsBottomY + editorState.rowOffset * padHeight - ui.EDITOR_BUTTON_BAR_HEIGHT;
  const editorHeight = ui.EDITOR_BUTTON_BAR_HEIGHT + ui.EDITOR_HEIGHT_IN_PADS * padHeight;

  editor.container.style.display = editorState.editingPatch || editorState.closing ? 'flex' : 'none';
  editor.container.style.height = `${editorHeight}px`;

  if (editorState.closing) {
    editor.container.style.top = `${editorClosedTop}px`;
    if (!editorState.closingListenerAdded) {
      editorState.closingListenerAdded = true;
      editor.container.addEventListener(
        'transitionend',
        () => {
          editorState.editingPatch = false;
          editorState.rowOffset = 0;
          editorState.closing = false;
          editorState.closingListenerAdded = false;
          editor.container.style.display = 'none';
        },
        { once: true }
      );
    }
  } else if (editorState.editingPatch && editorState.justOpened) {
    editor.container.style.top = `${editorClosedTop}px`;
    editorState.justOpened = false;
  } else if (editorState.editingPatch) {
    editor.container.style.top = `${editorOpenTop}px`;
  }

  topLevelThing.recursiveRender();
  topLevelThing.recursiveRenderOnTop();

  for (const finger of fingersById.values()) {
    finger.render();
  }

  for (const [note, voice] of midiNoteVoices.entries()) {
    const pad = pads.find((pad) => pad.note === note);
    if (pad) {
      renderMpeFinger(pad, voice);
    }
  }

  renderStatus();

  Finger.updateQuantizationOffsets();

  requestAnimationFrame(render);
}

render();

