function getPressure(e: PointerEvent) {
  if (e.pointerType === 'pen') {
    return e.pressure;
  } else if (e.pointerType === 'touch') {
    return Math.abs(Math.max(e.width, e.height) - 20) / (150 - 20);
  } else {
    return 1;
  }
}
