import { SAMPLE_RATE } from './constants';
import { canvas } from './canvas';
import { Font } from './ui-constants';

let initSynths: () => void;

export function toInitSynths(fn: () => void) {
  initSynths = fn;
}

export const context = new AudioContext({
  latencyHint: 'balanced',
  sampleRate: SAMPLE_RATE,
});

// @ts-ignore -- not a real error, see https://v3.vitejs.dev/guide/assets.html
import workletUrl from './msynth-worklet.ts?worker&url';
await context.audioWorklet.addModule(workletUrl);

let currentMicSource: MediaStreamAudioSourceNode | null = null;
let currentMicStream: MediaStream | null = null;
const micConsumers: AudioWorkletNode[] = [];

export function getCurrentMicSource(): MediaStreamAudioSourceNode | null {
  return currentMicSource;
}

export function registerMicConsumer(worklet: AudioWorkletNode): void {
  micConsumers.push(worklet);
  if (currentMicSource) {
    currentMicSource.connect(worklet);
  }
}

function showDevicePickerOverlay(): Promise<string | null> {
  return new Promise((resolve) => {
    const overlay = document.createElement('div');
    overlay.style.cssText = `
      position: fixed;
      inset: 0;
      z-index: 10000;
      display: flex;
      align-items: center;
      justify-content: center;
      background: rgba(0, 0, 0, 0.05);
      backdrop-filter: blur(3px);
      -webkit-backdrop-filter: blur(3px);
    `;
    const panel = document.createElement('div');
    panel.style.cssText = `
      width: 80%;
      max-width: 400px;
      border-radius: 8px;
      background: #fff;
      box-shadow: 0 20px 60px rgba(0,0,0,0.2);
      display: flex;
      flex-direction: column;
      overflow: hidden;
      padding: 20px;
      gap: 12px;
    `;

    const title = document.createElement('div');
    title.textContent = 'Select input device';
    title.style.cssText = `font: ${Font.button.cssFontString}; margin-bottom: 4px;`;
    panel.appendChild(title);

    const list = document.createElement('div');
    list.style.cssText = `display: flex; flex-direction: column; gap: 8px; max-height: 60vh; overflow-y: auto;`;
    panel.appendChild(list);

    const cancelBtn = document.createElement('button');
    cancelBtn.textContent = 'Cancel';
    cancelBtn.style.cssText = `font: ${Font.button.cssFontString}; margin-top: 8px; padding: 10px;`;
    cancelBtn.onclick = () => {
      overlay.remove();
      resolve(null);
    };
    panel.appendChild(cancelBtn);

    overlay.appendChild(panel);
    document.body.appendChild(overlay);

    navigator.mediaDevices.enumerateDevices().then((devices) => {
      const audioInputs = devices.filter((d) => d.kind === 'audioinput');
      if (audioInputs.length === 0) {
        const msg = document.createElement('div');
        msg.textContent = 'No audio input devices found.';
        msg.style.color = '#666';
        list.appendChild(msg);
        return;
      }
      for (const d of audioInputs) {
        const button = document.createElement('button');
        button.textContent = d.label || `Device ${d.deviceId.slice(0, 8)}`;
        button.style.cssText = `font: ${Font.button.cssFontString}; padding: 10px; text-align: left;`;
        button.onclick = () => {
          overlay.remove();
          resolve(d.deviceId);
        };
        list.appendChild(button);
      }
    });
  });
}

export async function setInputDevice(): Promise<MediaStreamAudioSourceNode | null> {
  const deviceId = await showDevicePickerOverlay();
  if (deviceId === null) {
    return null;
  }

  if (currentMicSource) {
    currentMicSource.disconnect();
    currentMicSource = null;
  }
  if (currentMicStream) {
    currentMicStream.getTracks().forEach((t) => t.stop());
    currentMicStream = null;
  }

  try {
    const stream = await navigator.mediaDevices.getUserMedia({
      audio: { deviceId: { exact: deviceId }, autoGainControl: false, echoCancellation: false },
    });
    currentMicStream = stream;
    currentMicSource = context.createMediaStreamSource(stream);
    for (const worklet of micConsumers) {
      currentMicSource.connect(worklet);
    }
    return currentMicSource;
  } catch (err) {
    console.warn('Failed to get user media:', err);
    return null;
  }
}

let webAudioState: 'need initialization' | 'initializing' | 'ready' = 'need initialization';

export function ensureWebAudioInitialized() {
  if (webAudioState === 'need initialization') {
    webAudioState = 'initializing';
    console.info('initializing web audio');
    initSynths();
    webAudioState = 'ready';
    console.info('web audio ready');
  }

  // When the iPad is turned off then turned back on, the audio context gets suspended.
  // We need to resume it, and that only works when done in response to a user interaction.
  if (context.state === 'suspended' || context.state === 'interrupted') {
    // Note: no await on purpose!
    console.info('resuming web audio!');
    context.resume();
  }
}
