export interface Position {
  x: number;
  y: number;
}

export const MODES = ['mpe', 'piano', 'string', 'strum'] as const;
export type Mode = (typeof MODES)[number];
export const isMode = (m: any): m is Mode => MODES.includes(m);

export const OCTAVES = [-2, -1, 0, 1, 2] as const;
export type Octave = (typeof OCTAVES)[number];
export const isOctave = (o: any): o is Octave => OCTAVES.includes(o);

export interface PatchSettings {
  name: string;
  mode: Mode;
  mono: boolean;
  octave: number;
  A: number;
  B: number;
  C: number;
  D: number;
  E: number;
  F: number;
  G: number;
  H: number;
  I: number;
  J: number;
  tempo?: number;
  triggerPeriod?: number;
  noteDuration?: number;
}

export type PatternName = 'A' | 'B';
export type Pattern = number[][];
export interface SequencerState {
  patternA: Pattern;
  patternB: Pattern;
  currPattern: PatternName;
  currStep: number;
  nextPattern: PatternName | '●';
  triggerPeriod: number; // in beats
  noteDuration: number; // between 0 and 1, a fraction of the trigger period
  playing: boolean;
}

export type MessageToWorklet =
  | { command: 'init'; voiceParams: SharedArrayBuffer[] }
  | { command: 'load patch'; code: string; mono: boolean }
  | { command: 'load ai modules'; code: string }
  | { command: 'process midi message'; data: Uint8Array }
  // sequencer commands
  | { command: 'set curr pattern'; pattern: PatternName }
  | { command: 'set next pattern'; pattern: PatternName | '●' }
  | { command: 'set pattern steps', pattern: PatternName; steps: Pattern }
  | { command: 'set trigger period'; value: number }
  | { command: 'set note duration'; value: number }
  | { command: 'start sequencer' }
  | { command: 'stop sequencer' }
  ;

export type MessageFromWorklet =
  | { event: 'log'; message: string }
  | { event: 'seq state'; state: SequencerState }
  | { event: 'seq step'; pattern: PatternName; index: number; action: 'noteOn' | 'noteOff' };
