import { parse } from './compiler';
import { PatchSettings } from './types';

export class Patch {
  static parse(code: string): Patch {
    const prog = parse(code);
    return new Patch(code, prog.settings);
  }

  private constructor(
    public code: string,
    public settings: PatchSettings,
  ) { }
}

export const patchLibrary: Patch[] = [
  Patch.parse(`
-- name: "rebel yell", octave: 1, mode: "mpe", A: 0, B: 0.1 --

mod = A lglide(t: 0.05) norm abs scale(min: 0.45, max: 0.55)
freq = noteFreq * (1 + (noise * B scale(min: 0, max: 0.2)))
dry = freq pulse(w: mod) lpf(cf: 6000, q: 0.2) adsr(a: 0.03, d: 0, s: 1, r: 0.1)
out = dry + 0.5 * dry delay(t: 0.4)
  `),
  Patch.parse(`
-- name: "hello again", octave: -1 --

osc1 = (noteFreq / 4) pulse
osc2 = 300 ad(a: 0.2, d: 0.5) >> pulse(w: 0.5, sync: osc1)
out = osc2 adsr(a: 0.05, d: 0, s: 1, r: 0.2) >> dcBlock
  `),
  Patch.parse(`
-- name: "duran duran", mono: true, mode: "piano", tempo: 113, triggerPeriod: 0.125, C: 0.95, D: 0.2 --

delayAmt = 0.6
detuneAmt = D
portamento = A
freq = (B abs - 0.5) switch2(pos: noteFreq * 2, neg: noteFreq) eglide(t: portamento)
f1 = freq / 2
f2 = freq * detuneAmt escale(min: 1.001, max: 1.025)
oscs = 0.3 * f1 pulse + 0.7 * f2 pulse
dry = oscs lpf12(cf: 24000 * C, q: 1) ad(a: 0, d: 1 beats)
out = dry + delayAmt * dry delay(t: 0.75 beats)
  `),
  Patch.parse(`
-- name: "stranger things", octave: -2, A: 0.8, B: 0.5, tempo: 84, triggerPeriod: 0.0625, noteDuration: 0.5 --

cf = 10000 adsr(a: 0.001, d: 0, s: 1, r: 0.5)
q = (B norm - 0.5) abs scale(min: 0.15, max: 1)
pwmRate = 0.218
osc1 = noteFreq pulse(w: pwmRate sine norm scale(min: 0.2, max: 0.8))
osc2 = (2 * noteFreq * 1.005) pulse(w: pwmRate sine norm scale(min: 0.4, max: 0.6))
out = (osc1 + osc2) lpf(cf, q) adsr(a: 0, d: 0, s: 1, r: A) >> dcBlock
  `),
  Patch.parse(`
-- name: "tom sawyer", octave: -2, A: 0.755, B: 0.127 --

w = 0.5 + (1/5) sine norm scale(min: 0, max: 0.4)
detune1 = 0.091 * 0.01
detune2 = 0.836 * 0.01
delayAmt = B
oscs =
  (
    (noteFreq * (1 - detune1)) pulse(w) +
    (noteFreq * (1 + detune1)) pulse(w) +
    (noteFreq * (1 - 3 * detune2)) pulse(w) +
    (noteFreq * (1 + 3 * detune2)) pulse(w)
  ) / 4
cf = 10000 * (adsr(a: 0.05, d: 0, s: 1, r: 6) escale(min: 0, max: 1))
dry = oscs lpf12(cf, q: A) adsr(a: 0, d: 0, s: 1, r: 12)
out = dry + delayAmt * dry delay(t: 0.15) >> dcBlock
  `),
  Patch.parse(`
-- name: "guitar", octave: -1, A: 1, B: 0.99 --

cutoff = A
feedback = B scale(min: 0.9, max: 0.999)
burst  = noise ad(a: 0, d: 0.01) * noteVel
filter = (burst + filter) delay(t: 1 / noteFreq) lpf12(cf: 20000 * cutoff, q: 0) * feedback
out = burst + filter adsr(a: 0, d: 0, s: 1, r: 0.1)
  `),
  Patch.parse(`
-- name: "12 string", octave: -1, A: 1, B: 0.99, mode: "strum" --

cutoff = A
feedback = B scale(min: 0.9, max: 0.999)
burst  = noise ad(a: 0, d: 0.01) * noteVel
string1 = (burst + string1) delay(t: 1 / noteFreq) lpf12(cf: 20000 * cutoff, q: 0) * feedback
string2 = (burst + string2) delay(t: 1 / (noteFreq * 2)) lpf12(cf: 20000 * cutoff, q: 0) * feedback
out = burst + (string1 + string2) adsr(a: 0, d: 0, s: 1, r: 0.1)
  `),
  Patch.parse(`
-- name: "strum bass", octave: -2, A: 0.2, B: 1, mode: "strum" --

out = noteFreq sine adsr(a: 0.01, d: 0.01, s: 1, r: 0.1)
  `),
  Patch.parse(`
-- name: "rick and morty", tempo: 83 --

sound1 = noise bpf(cf: 0.2 sine * 800 + 1200, q: 1)
sound2 = noise bpf(cf: -(0.25 sine) * 800 + 1200, q: 1)
ring = (sound1 + sound1 delay(t: 2) + sound2) * (1 / 0.25 beats) pulse norm * 0.5
out = ring adsr(a: 0.01, d: 0, s: 1, r: 2)
  `),
  Patch.parse(`
-- name: "bells", mode: "piano" --

// param A controls the harmonic ratio
f1 = noteFreq
f2 = f1 * 2.5
out = f1 sine * f2 sine >> ad(a: 0.001, d: .5)
  `),
  Patch.parse(`
-- name: "pwm" --

out = noteFreq pulse(w: slide lglide(t: 0.05) norm scale(min: 0.2, max: 0.8)) adsr(a: 0.05, d: 0, s: 1, r: 0.4)
  `),
  Patch.parse(`
-- name: "pwm pencil" --

out = noteFreq pulse(w: slide lglide(t: 0.05) norm scale(min: 0.2, max: 0.8)) adsr(a: 0.05, d: 0, s: 1, r: 0.4) * pressure
  `),
  Patch.parse(`
-- name: "sine" --

out = noteFreq sine adsr(a: 0.01, d: 0, s: 1, r: 0.3)
  `),
  Patch.parse(`
-- name: "ddd", octave: 0, mode: "mpe", A: 0.5, B: 0.5, C: 0.5, D: 0.5 --

preDistGain = A scale(min: 0.1, max: 5)
postDistGain = B * 10
directSignalGain = (slide - 0.5) abs * 3
feedbackGain = C scale(min: 0, max: 0.9)
feedbackDelay = 0.1 * D

in = noteFreq saw adsr(a: 0.03, d: 0, s: 1, r: 0.1)

nonLinearDist = (in * preDistGain + feedback) >> softClip
feedback = nonLinearDist * feedbackGain >> delay(t: feedbackDelay)
out = nonLinearDist * postDistGain + in * directSignalGain
  `),
  Patch.parse(`
-- name: "harmonizer", octave: 0, mode: "mpe" --

out = input gate pitchShift(readSpeed: (noteNum - 60) semitones)
  `),
  Patch.parse(`
-- name: "user 1", octave: 0, mode: "mpe" --

out = noteFreq saw gate
  `),
  Patch.parse(`
-- name: "user 2", octave: 0, mode: "mpe" --

out = noteFreq sine adsr(a: 0.01, d: 0, s: 1, r: 0.3)
  `),
  Patch.parse(`
-- name: "user 3", octave: 0, mode: "mpe" --

out = noteFreq sine adsr(a: 0.01, d: 0, s: 1, r: 0.3)
  `),
];
