import type { Position } from './types';

import * as ui from './ui-constants';
import { Font } from './ui-constants';
import { TAU } from './constants';
import { canvas, ctx, showStatus } from './canvas';
import { clamp } from './helpers';
import { drawMaterialOverlay } from './ui-texture';
import { ensureWebAudioInitialized } from './audio';

export type PosHint = 'next' | 'top left' | 'top center' | 'top right' | 'bottom left' | 'bottom center' | 'bottom right' | 'as is';

export type ThingOptions = {
  x?: () => number;
  y?: () => number;
  w?: () => number;
  h?: () => number;
  layoutMode?: 'row' | 'column' | 'none'
  isActive?: () => boolean;
  hasBackground?: boolean;
}

export abstract class Thing<Options extends ThingOptions = ThingOptions> {
  protected parent: Thing | null = null;
  protected readonly children: Thing[] = [];
  protected readonly posHints: PosHint[] = [];
  public x = 0;
  public y = 0;
  public w = 0;
  public h = 0;

  constructor(public readonly options: Options) { }

  addChild(child: Thing, posHint: PosHint = 'next'): this {
    child.parent = this;
    this.children.push(child);
    this.posHints.push(posHint);
    this.layout();
    return this;
  }

  replaceChild(oldChild: Thing, newChild: Thing): this {
    const index = this.children.indexOf(oldChild);
    if (index === -1) {
      throw new Error('oldChild not found');
    }
    this.children[index] = newChild;
    newChild.parent = this;
    this.layout();
    return this;
  }

  // ----- position and size -----

  layout() {
    let nextX = this.x;
    let nextY = this.y;
    for (let idx = 0; idx < this.children.length; idx++) {
      const child = this.children[idx];
      const posHint = this.posHints[idx];

      child.x = child.options.x?.() ?? child.x;
      child.y = child.options.y?.() ?? child.y;
      child.w = child.options.w?.() ?? child.w;
      child.h = child.options.h?.() ?? child.h;

      switch (posHint) {
        case 'next':
          child.x = nextX;
          child.y = nextY;
          switch (this.options.layoutMode ?? 'none') {
            case 'row':
              child.h = this.h;
              nextX += child.w;
              break;
            case 'column':
              child.w = this.w;
              nextY += child.h;
              break;
            case 'none':
              throw new Error('cannot have a child w/ posHint "next" when layoutMode is "none"');
          }
          break;
        case 'top left':
          child.x = this.x;
          child.y = this.y;
          break;
        case 'top center':
          child.x = this.centerX - child.w / 2;
          child.y = this.y;
          break;
        case 'top right':
          child.x = this.rightX - child.w;
          child.y = this.y;
          break;
        case 'bottom left':
          child.x = this.x;
          child.y = this.bottomY - child.h;
          break;
        case 'bottom center':
          child.x = this.centerX - child.w / 2;
          child.y = this.bottomY - child.h;
          break;
        case 'bottom right':
          child.x = this.rightX - child.w;
          child.y = this.bottomY - child.h;
          break;
        case 'as is':
          // leave child.x and child.y alone
          break;
      }
      child.layout();
    }
  }

  get bottomY() {
    return this.y + this.h;
  }

  get rightX() {
    return this.x + this.w;
  }

  get centerY() {
    return this.y + this.h / 2;
  }

  get centerX() {
    return this.x + this.w / 2;
  }

  contains(x: number, y: number) {
    return this.x <= x && x <= this.rightX && this.y <= y && y <= this.bottomY;
  }

  // rendering

  render() {
    if (this.options.hasBackground) {
      ctx.beginPath();
      ctx.fillStyle = '#ddd';
      ctx.rect(this.x, this.y, this.w, this.h);
      ctx.fill();

      ctx.globalAlpha = this.lightBackgroundAlpha;
      ctx.beginPath();
      ctx.fillStyle = this.lightBackgroundColor;
      ctx.roundRect(this.x + 1, this.y + 1, this.w - 2, this.h - 2, ui.RECTANGLE_RADIUS);
      ctx.fill();

      ctx.globalAlpha = 1;
      drawMaterialOverlay(this.x + 1, this.y + 1, this.w - 2, this.h - 2, ui.RECTANGLE_RADIUS);
    }
  }

  get lightBackgroundAlpha() {
    return 1;
  }

  /** Subclasses may override this method to render overlays, etc. */
  renderOnTop() { }

  /** This method should be `final`, but that doesn't exist in TypeScript :/ */
  recursiveRender() {
    ctx.save();
    ctx.beginPath();
    ctx.rect(this.x, this.y, this.w, this.h);
    ctx.clip();

    ctx.save();
    this.render();
    ctx.restore();

    for (const child of this.children) {
      child.recursiveRender();
    }

    ctx.restore();
  }

  /**
   * Unlike render(), renderOnTop() doesn't clip. It also does the children before the parent.
   * This method should be `final`, but that doesn't exist in TypeScript :/
   */
  recursiveRenderOnTop() {
    for (const child of this.children) {
      child.recursiveRenderOnTop();
    }

    ctx.save();
    this.renderOnTop();
    ctx.restore();
  }

  // event handling

  /** Returns `this` if the event was handled here. */
  onPointerDown(x: number, y: number, e: PointerEvent): this | null {
    return null;
  }

  onPointerMove(x: number, y: number, e: PointerEvent) { }

  onPointerUp(x: number, y: number, e: PointerEvent): void { }

  /** This method should be `final`, but that doesn't exist in TypeScript :/ */
  recursiveOnPointerDown(x: number, y: number, e: PointerEvent): Thing | null {
    if (!this.contains(x, y)) {
      return null;
    }

    for (const child of this.children) {
      const childThatGotIt = child.recursiveOnPointerDown(x, y, e);
      if (childThatGotIt) {
        return childThatGotIt;
      }
    }

    return this.onPointerDown(x, y, e);
  }

  // colors, etc.

  get backgroundColor() {
    return ui.DARK_BACKGROUND_COLOR;
  }

  get lightBackgroundColor() {
    return ui.LIGHT_BACKGROUND_COLOR;
  }

  get foregroundColor() {
    return ui.TEXT_COLOR
  }

  // helpers

  textWidth(text: string, font: Font) {
    ctx.save();
    ctx.font = font.cssFontString;
    const width = ctx.measureText(text).width;
    ctx.restore();
    return width;
  }

  renderLabel(label: string, font = Font.button, x?: number, y?: number, color?: string, alpha?: number) {
    ctx.save();
    ctx.globalAlpha = alpha ?? (this.isActive ? 1 : 0.5);
    ctx.beginPath();
    ctx.font = font.cssFontString;
    ctx.fillStyle = color ?? this.foregroundColor;
    const px = x ?? this.centerX;
    const py = y ?? this.centerY;
    ctx.fillText(label, px - ctx.measureText(label).width / 2, py + font.baselineAdjustment);
    ctx.fill();
    ctx.restore();
  }

  get isActive(): boolean {
    return this.options.isActive?.() ?? this.parent?.isActive ?? false;
  }
}

export const topLevelThing = new (class extends Thing {
  constructor() {
    super({
      layoutMode: 'none',
      x: () => 0,
      y: () => 0,
      w: () => innerWidth,
      h: () => innerHeight,
    });
  }

  recursiveRender() {
    const w = this.options.w!();
    const h = this.options.h!();
    if (this.w !== w || this.h !== h) {
      this.w = w;
      this.h = h;
      this.layout();
    }

    super.recursiveRender();
  }
})();

export class Slot extends Thing {
  private currentChild: Thing;

  constructor(private readonly supplier: () => Thing) {
    super({
      layoutMode: 'none',
      w: () => this.childSize().w,
      h: () => this.childSize().h,
    });
    this.currentChild = this.supplier();
    this.addChild(this.currentChild, 'top left');
  }

  /** Ensures the child has dimensions before we report our size (parent asks before layout runs). */
  private childSize(): { w: number; h: number } {
    const c = this.children[0];
    if (!c) {
      return { w: 0, h: 0 };
    }
    const w = c.options.w?.() ?? c.w;
    const h = c.options.h?.() ?? c.h;
    return { w, h };
  }

  layout() {
    const c = this.children[0];
    if (c) {
      // Slot's child must fill the slot; parent allocates our w/h, so assign them to the child.
      // Otherwise children without explicit options.h (e.g. Display/Tool) stay at h=0 and get clipped.
      c.w = this.w;
      c.h = this.h;
    }
    super.layout();
  }

  /** Called each frame before render; updates the child if the supplier returns a different Thing. */
  recursiveRender() {
    const next = this.supplier();
    if (next !== this.currentChild) {
      this.replaceChild(this.currentChild, next);
      this.currentChild = next;
      this.parent?.layout();  // propagate layout up when content changes size
    }
    super.recursiveRender();
  }
}

export class Row extends Thing {
  constructor(options: ThingOptions) {
    super({ layoutMode: 'row', w: () => this.children.reduce((acc, child) => acc + child.w, 0), ...options });
  }
}

export class Column extends Thing {
  constructor(options: ThingOptions) {
    super({ layoutMode: 'column', h: () => this.children.reduce((acc, child) => acc + child.h, 0), ...options });
  }
}

interface ButtonOptions extends ThingOptions {
  label: () => string;
  pointerDownFn?: () => void;
  pointerUpFn?: () => void;
}

export class Button extends Thing<ButtonOptions> {
  constructor(options: ButtonOptions) {
    super({ hasBackground: true, ...options });
  }

  render() {
    super.render();
    this.renderLabel(this.options.label());
  }

  onPointerDown() {
    this.options.pointerDownFn?.();
    return this;
  }

  onPointerUp() {
    this.options.pointerUpFn?.();
    return this;
  }
}

export interface KnobOptions extends ThingOptions {
  label: string;
  getValue: () => number;
  setValue: (x: number) => void;
  color: () => string;
}

export class Knob extends Thing<KnobOptions> {
  constructor(options: KnobOptions) {
    super({ hasBackground: true, ...options });
  }

  render() {
    super.render();

    const radius = 0.3 * Math.min(this.w, this.h);

    ctx.lineWidth = 5;

    ctx.globalAlpha = this.isActive ? 0.2 : 0.1;
    ctx.beginPath();
    ctx.strokeStyle = this.isActive ? this.options.color() : this.backgroundColor;
    ctx.lineCap = 'butt';
    ctx.arc(this.centerX, this.centerY, radius, 0, TAU);
    ctx.stroke();

    ctx.globalAlpha = this.isActive ? 1 : 0.5;
    ctx.beginPath();
    ctx.arc(this.centerX, this.centerY, radius, TAU / 4, TAU * this.value + TAU / 4);
    ctx.stroke();

    this.renderLabel(this.options.label, Font.selector);
  }

  get value() {
    return this.options.getValue();
  }

  set value(newValue: number) {
    this.options.setValue(newValue);
  }

  private angle0: number | null = null;
  private isTouch = false;

  renderOnTop(): void {
    if (!this.angle0 || !this.isTouch) {
      return;
    }

    ctx.save();
    ctx.globalAlpha = 0.8;
    ctx.translate(1.25 * this.w, 0);
    this.render();
    ctx.restore();
  }

  onPointerDown(x: number, y: number, { pointerType }: PointerEvent) {
    this.angle0 = Math.atan2(y - this.centerY, x - this.centerX);
    this.isTouch = pointerType === 'touch';
    return this;
  }

  onPointerMove(x: number, y: number) {
    const newAngle = Math.atan2(y - this.centerY, x - this.centerX);
    const diff = ((((newAngle - this.angle0! + Math.PI) % TAU) + TAU) % TAU) - Math.PI;
    const value = clamp(this.value + diff / TAU, 0, 1);
    this.options.setValue(value);
    this.angle0 = newAngle;
    showStatus(`${this.options.label} = ${value.toFixed(2)}`);
  }

  onPointerUp(x: number, y: number): void {
    this.angle0 = null;
  }
}

interface ScrubberOptions extends ThingOptions {
  label?: (value: number) => string;
  minValue?: number;
  maxValue?: number;
  getValue: () => number;
  setValue: (newValue: number) => void;
}

export class Scrubber extends Thing<ScrubberOptions> {
  constructor(options: ScrubberOptions) {
    super({ hasBackground: true, ...options });
  }

  render() {
    super.render();
    this.renderLabel(this.options.label?.(this.options.getValue()) ?? `${this.options.getValue()}`);
  }

  x0: number | null = null;
  value0: number | null = null;

  onPointerDown(x: number, y: number) {
    this.x0 = x;
    this.value0 = this.options.getValue();
    return this;
  }

  onPointerMove(x: number, y: number) {
    const dx = x - this.x0!;
    this.options.setValue(clamp(Math.round(this.value0! + dx / 10), this.options.minValue ?? 0, this.options.maxValue ?? 100));
  }
}

export interface JoystickOptions extends ThingOptions {
  label: string;
  getXValue: () => number;
  setXValue: (x: number) => void;
  getYValue: () => number;
  setYValue: (y: number) => void;
  color: () => string;
}

export class Joystick extends Thing<JoystickOptions> {
  private readonly radius = 8;
  private static readonly labelPad = 2;
  private static readonly labelMargin = 2; // extra gap between circle and label

  constructor(options: JoystickOptions) {
    super({ hasBackground: true, ...options });
  }

  /** Label prefers widget center; only moves out of the way when the circles would overlap it. */
  private labelPosition(cx: number, cy: number): { px: number; py: number } {
    const font = Font.joystick;
    const labelW = this.textWidth(this.options.label, font);
    const labelH = font.sizeInPixels;
    const pad = Joystick.labelPad;
    const minLabelW = this.w - 2 * pad;
    const halfW = Math.min(labelW / 2, minLabelW / 2);
    const halfH = Math.max(font.sizeInPixels - font.baselineAdjustment, font.baselineAdjustment);

    const left = this.x + pad + halfW;
    const right = this.rightX - pad - halfW;
    const top = this.y + pad - font.baselineAdjustment + labelH;
    const bottom = this.bottomY - pad - font.baselineAdjustment;

    // Preferred: centered in the widget
    let px = this.centerX;
    let py = this.centerY;

    // Would the label at center overlap the circle?
    const nearestToCircleX = clamp(cx, px - halfW, px + halfW);
    const nearestToCircleY = clamp(cy, py - halfH, py + halfH);
    const distToCircle = Math.hypot(cx - nearestToCircleX, cy - nearestToCircleY);

    if (distToCircle < this.radius) {
      // Move label away from the circle (from circle toward center, then past so they don't touch)
      let ux = this.centerX - cx;
      let uy = this.centerY - cy;
      const len = Math.hypot(ux, uy);
      if (len < 1e-6) {
        ux = 0;
        uy = 1;
      } else {
        ux /= len;
        uy /= len;
      }
      const minOffset = this.radius + halfW * Math.abs(ux) + halfH * Math.abs(uy) + Joystick.labelMargin;
      px = cx + minOffset * ux;
      py = cy + minOffset * uy;
      px = clamp(px, left, right);
      py = clamp(py, top, bottom);
      // If clamping pulled it back into the circle, push out again (may go slightly outside box)
      const againX = clamp(cx, px - halfW, px + halfW);
      const againY = clamp(cy, py - halfH, py + halfH);
      if (Math.hypot(cx - againX, cy - againY) < this.radius) {
        px = cx + minOffset * ux;
        py = cy + minOffset * uy;
      }
    }

    return { px, py };
  }

  render() {
    super.render();

    const xValue = this.options.getXValue();
    const yValue = this.options.getYValue();

    const cx = this.x + this.radius + xValue * (this.w - 2 * this.radius);
    const cy = this.bottomY - this.radius - yValue * (this.h - 2 * this.radius);

    ctx.globalAlpha = this.isActive ? 0.25 : 0.125;
    ctx.fillStyle = this.isActive ? this.options.color() : this.backgroundColor;
    ctx.beginPath();
    ctx.arc(cx, cy, this.radius, 0, TAU);
    ctx.fill();

    ctx.globalAlpha = this.isActive ? 1 : 0.5;
    ctx.beginPath();
    ctx.arc(cx, cy, this.radius / 2, 0, TAU);
    ctx.fill();

    const { px, py } = this.labelPosition(cx, cy);
    this.renderLabel(this.options.label, Font.joystick, px, py);
  }

  private pos0: Position | null = null;
  private value0: Position | null = null;
  private isTouch = false;

  renderOnTop(): void {
    if (!this.pos0 || !this.isTouch) {
      return;
    }

    ctx.save();
    ctx.globalAlpha = 0.8;
    ctx.translate(1.25 * this.w, 0);
    this.render();
    ctx.restore();
  }

  onPointerDown(x: number, y: number, { pointerType }: PointerEvent) {
    this.pos0 = { x, y };
    this.value0 = { x: this.options.getXValue(), y: this.options.getYValue() };
    this.isTouch = pointerType === 'touch';
    return this;
  }

  onPointerMove(x: number, y: number) {
    const xv = clamp(this.value0!.x + (x - this.pos0!.x) / (this.w - this.radius * 2), 0, 1);
    const yv = clamp(this.value0!.y - (y - this.pos0!.y) / (this.h - this.radius * 2), 0, 1);
    this.options.setXValue(xv);
    this.options.setYValue(yv);
    showStatus(`${this.options.label} = (${xv.toFixed(2)}, ${yv.toFixed(2)})`);
  }

  onPointerUp(x: number, y: number) {
    this.pos0 = null;
    this.value0 = null;
  }
}

interface LabelOptions extends ThingOptions {
  label: () => string;
  color?: () => string;
  onPointerDown?: () => Thing | null;
  onPointerUp?: () => void;
}

export class Label extends Thing<LabelOptions> {
  constructor(options: LabelOptions) {
    super({
      w: () => this.textWidth(this.options.label()) + 2 * ui.EMBEDDED_SELECTOR_PADDING,
      h: () => Font.selector.sizeInPixels + 2 * ui.EMBEDDED_SELECTOR_PADDING,
      ...options
    });
  }

  onPointerDown() {
    this.options?.onPointerDown?.();
    return this;
  }

  onPointerUp() {
    this.options?.onPointerUp?.();
  }

  get foregroundColor() {
    return this.options.color?.() ?? this.foregroundColor;
  }

  render() {
    super.render();
    this.renderLabel(this.options.label(), Font.selector);
  }

  textWidth(text: string, font = Font.selector) {
    return super.textWidth(text, font);
  }
}

interface EmbeddedSelectorOptions<T> extends ThingOptions {
  values: readonly T[];
  getValue: () => T;
  setValue: (value: T) => void;
  valueToString: (value: T) => string;
  placeCurrentValueAtY0?: boolean;
  color?: string;
}

export class EmbeddedSelector<T> extends Thing<EmbeddedSelectorOptions<T>> {
  private readonly lineSpacing = 1.25;
  private readonly labels: string[];
  private readonly maxLabelWidth: number;

  constructor(options: EmbeddedSelectorOptions<T>) {
    super({
      w: () => this.textWidth(this.options.valueToString(this.options.getValue())) + 2 * ui.EMBEDDED_SELECTOR_PADDING,
      h: () => Font.selector.sizeInPixels + 2 * ui.EMBEDDED_SELECTOR_PADDING,
      ...options,
    });

    const { values, valueToString, placeCurrentValueAtY0 } = options;

    this.labels = values.map(valueToString);
    if (!placeCurrentValueAtY0) {
      this.labels.unshift('');
    }

    this.maxLabelWidth = this.labels
      .map((label) => this.textWidth(label))
      .reduce((a, b) => Math.max(a, b)) + 2 * ui.EMBEDDED_SELECTOR_PADDING;
  }

  private pointerPos?: { initial: Position; current: Position };
  private popUp?: { x: number, y: number, w: number, h: number };
  private selection?: { x: number, y0: number };

  onPointerDown(x: number, y: number) {
    this.pointerPos = { initial: { x, y }, current: { x, y } };

    const goRight = this.pointerPos.initial.x < innerWidth / 2;

    const w = 1.125 * ui.SELECTOR_FINGER_WIDTH + this.maxLabelWidth;
    this.popUp = {
      w,
      h: (this.labels.length + 0.5) * Font.selector.sizeInPixels * this.lineSpacing,
      x: goRight
        ? this.pointerPos.initial.x - ui.SELECTOR_FINGER_WIDTH / 2
        : this.pointerPos.initial.x - w + ui.SELECTOR_FINGER_WIDTH / 2,
      y: this.pointerPos.initial.y - Font.selector.sizeInPixels
    };

    if (this.options.placeCurrentValueAtY0) {
      this.popUp.y -= Font.selector.sizeInPixels * this.options.values.indexOf(this.options.getValue());
    }

    this.selection = {
      x: this.popUp.x + (goRight ? ui.SELECTOR_FINGER_WIDTH : 0.125 * ui.SELECTOR_FINGER_WIDTH),
      y0: this.popUp.y + (this.options.placeCurrentValueAtY0 ? 0 : Font.selector.sizeInPixels),
    };

    return this;
  }

  onPointerMove(x: number, y: number) {
    this.pointerPos!.current.x = x;
    this.pointerPos!.current.y = y;
    const firstValueY = this.popUp.y + (this.options.placeCurrentValueAtY0 ? 1 : 2) * Font.selector.sizeInPixels;
    const selectedValueIdx = Math.round((y - firstValueY) / (Font.selector.sizeInPixels * this.lineSpacing));
    if (selectedValueIdx < 0) {
      return;
    }
    const selectedValue = this.options.values[Math.min(selectedValueIdx, this.options.values.length - 1)];
    if (selectedValue !== this.options.getValue()) {
      this.options.setValue(selectedValue);
      this.parent.layout();  // necessary b/c our width changes
    }
  }

  onPointerUp(x: number, y: number): void {
    this.pointerPos = undefined;
  }

  render() {
    this.parent.layout();
    this.renderLabel(this.options.valueToString(this.options.getValue()), Font.selector);
  }

  renderOnTop() {
    if (!this.pointerPos) {
      return;
    }

    ctx.fillStyle = 'rgba(255, 255, 255, 0.75)';
    ctx.filter = 'drop-shadow(2px 2px 2px)';
    ctx.beginPath();
    ctx.roundRect(this.popUp.x, this.popUp.y, this.popUp.w, this.popUp.h, ui.RECTANGLE_RADIUS);
    ctx.fill();
    ctx.filter = 'none';

    ctx.filter = 'blur(5px)';
    ctx.fillStyle = 'rgba(255, 255, 255, 0.8)';
    ctx.beginPath();
    ctx.roundRect(this.popUp.x, this.popUp.y, this.popUp.w, this.popUp.h, ui.RECTANGLE_RADIUS);
    ctx.fill();
    ctx.filter = 'none';

    ctx.font = Font.selector.cssFontString;
    let valueY = this.selection.y0;
    for (const value of this.options.values) {
      valueY += Font.selector.sizeInPixels * this.lineSpacing;
      this.renderValue(
        this.options.valueToString(value),
        this.options.getValue() === value,
        this.selection.x,
        valueY,
      );
    }
  }

  renderValue(label: string, isCurrent: boolean, x: number, y: number) {
    if (isCurrent) {
      ctx.beginPath();
      ctx.fillStyle = ui.LIGHT_BACKGROUND_COLOR;
      ctx.roundRect(
        x - ui.EMBEDDED_SELECTOR_PADDING,
        y - Font.selector.sizeInPixels,
        this.maxLabelWidth + 2 * ui.EMBEDDED_SELECTOR_PADDING,
        Font.selector.sizeInPixels + Font.selector.baselineAdjustment,
        ui.RECTANGLE_RADIUS,
      );
      ctx.fill();
    }

    ctx.beginPath();
    ctx.fillStyle = isCurrent ? '#000' : '#777';
    ctx.fillText(label, x, y);
    ctx.fill();
  }

  textWidth(text: string, font = Font.selector) {
    return super.textWidth(text, font);
  }

  get foregroundColor() {
    return this.options.color ?? ui.TEXT_COLOR;
  }
}

// handling pointer events

const pointerIdToThing = new Map<number, Thing>();

canvas.addEventListener('pointerdown', (e) => {
  ensureWebAudioInitialized();
  const thing = topLevelThing.recursiveOnPointerDown(e.offsetX, e.offsetY, e);
  if (thing) {
    pointerIdToThing.set(e.pointerId, thing);
    canvas.setPointerCapture(e.pointerId);
    e.preventDefault();

    // e.stopImmediatePropagation();
    // console.log('FYI a thing ate up a pointer down event');

    // always calling onPointerMove after onPointerDown makes my code nicer
    thing.onPointerMove(e.offsetX, e.offsetY, e);
  }
});

canvas.addEventListener('pointermove', (e) => {
  const thing = pointerIdToThing.get(e.pointerId);
  if (thing) {
    thing.onPointerMove(e.offsetX, e.offsetY, e);
    e.preventDefault();
  }
});

canvas.addEventListener('pointerup', onPointerUp);
canvas.addEventListener('pointercancel', onPointerUp);

function onPointerUp(e: PointerEvent) {
  const thing = pointerIdToThing.get(e.pointerId);
  if (thing) {
    thing.onPointerUp(e.offsetX, e.offsetY, e);
    pointerIdToThing.delete(e.pointerId);
    e.preventDefault();
  }
  canvas.releasePointerCapture(e.pointerId);
}
